"use strict";parserFactory.register("teenfic.net",()=>new TeenficParser);class TeenficParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=[...e.querySelectorAll("ul.chapters")].pop();return util.hyperlinksToChapterList(t)}findContent(e){return e.querySelector("div.chapter-content")}extractTitleImpl(e){return e.querySelector("h1.title")}extractAuthor(e){let t=e.querySelector("a[itemprop='author']");return t?.textContent??super.extractAuthor(e)}findChapterTitle(e){return e.querySelector(".chapter-title")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"#story-detail")}async fetchChapter(e){let t=(await HttpClient.wrapFetch(e)).responseXML,r=this.findContent(t),n=this.findOtherPagesOfChapter(t);for(let e of n){let t=(await HttpClient.wrapFetch(e)).responseXML,n=this.findContent(t);util.moveChildElements(n,r)}return t}findOtherPagesOfChapter(e){let t=new Set,r=[],n=[...e.querySelectorAll("ul.page li:not(.active) a")].map(e=>e.href);for(let e of n)t.has(e)||(r.push(e),t.add(e));return r}getInformationEpubItemChildNodes(e){return[e.querySelector("div.description")]}}